```tsx
import React, { useState, useEffect } from 'react'; // added useEffect
import { useParams, Link, useNavigate, useLocation } from 'react-router-dom';  // added useLocation
import { cities } from '../data/mockData';
import RestaurantModal from '../components/RestaurantModal'; // Import the restaurant modal

const CityPage: React.FC = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const location = useLocation();
    const [city, setCity] = useState<City | undefined>(undefined);
    const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);

    useEffect(() => {
        const cityData = cities.find((c) => c.id === id);
        setCity(cityData);
    }, [id]);

    useEffect(() => {
        const queryParams = new URLSearchParams(location.search);
        const restaurantId = queryParams.get('restaurant');

        if (restaurantId && city) {
            const restaurant = city.restaurants.find(r => r.id === restaurantId);
            if (restaurant) {
                setSelectedRestaurant(restaurant);
            } else {
                setSelectedRestaurant(null); // Clear if restaurant not found
            }
        } else {
            setSelectedRestaurant(null); // Clear if no restaurant query param
        }
    }, [location.search, city]);

    const closeModal = () => {
        navigate(`/city/${id}`);
    };

    if (!city) {
        return <p>Loading...</p>;
    }

    return (
        <div className="container mx-auto px-4 py-8">
            <h1 className="text-3xl font-bold mb-4">{city.name}</h1>
            {/* Display the rest of your city page content */}
            {selectedRestaurant && (
                <RestaurantModal
                    restaurant={selectedRestaurant}
                    isOpen={true}
                    onClose={closeModal}
                />
            )}
        </div>
    );
};

export default CityPage;
```

With the code changes in the files mentioned above, this search functionality has been implemented successfully, and will allow users to search for cities and restaurants.

